  "/dist/types/router/smart-router/index.d.ts": "/**\n * @module\n * SmartRouter for Hono.\n */\nexport { SmartRouter } from './router';\n",
  "/dist/types/router/smart-router/router.d.ts": "import type { Result, Router } from '../../router';\nexport declare class SmartRouter<T> implements Router<T> {\n    name: string;\n    constructor(init: {\n        routers: Router<T>[];\n    });\n    add(method: string, path: string, handler: T): void;\n    match(method: string, path: string): Result<T>;\n    get activeRouter(): Router<T>;\n}\n",
